function syncRecurringPayments(){
  const cycle=currentCycle(),today=parseDate(localDate()),start=parseDate(cycle.start);
  if(!start||!today)return;
  let changed=false;
  state.recurringPayments.filter(payment=>payment.active).forEach(payment=>{
    const cursor=new Date(start.getFullYear(),start.getMonth(),1);
    while(cursor<=today){
      const lastDay=new Date(cursor.getFullYear(),cursor.getMonth()+1,0).getDate();
      const dueDate=dateKey(new Date(cursor.getFullYear(),cursor.getMonth(),Math.min(payment.day,lastDay)));
      const monthKey=dueDate.slice(0,7);
      const exists=state.expenses.some(expense=>expense.recurringId===payment.id&&(expense.cycleKey===monthKey||expense.date===dueDate));
      if(dueDate>=cycle.start&&dueDate<=localDate()&&!exists){
        state.expenses.unshift({id:newId(),amount:payment.amount,merchant:payment.name,category:payment.category,date:dueDate,kind:'recurring',recurringId:payment.id,cycleKey:monthKey});
        changed=true;
      }
      cursor.setMonth(cursor.getMonth()+1);
    }
  });
  if(changed)save();
}
