function goalScheduleText(profile,saving){
  if(profile.goalType!=='specific'||!profile.goalAmount)return'';
  const progress=savingsProgress(profile.goalAmount,state.cycleReports);
  const progressText=`${tr('goalSavedSoFar')}: <b class="good">${money(progress.saved)}</b> • ${tr('goalRemaining')}: <b>${money(progress.remaining)}</b>.`;
  if(!saving)return`${progressText} ${tr('savingZero')}`;
  const estimated=Math.ceil(progress.remaining/saving);
  if(!profile.goalMonths)return`${progressText} ${tr('needMonths')} <b>${estimated}</b> ${tr('months')}.`;
  const required=progress.remaining/profile.goalMonths;
  return state.settings.lang==='ar'
    ?`${progressText} للوصول خلال <b>${fmt(profile.goalMonths)}</b> شهر تحتاج <b>${money(required)}</b> شهرياً. بخطتك الحالية تحتاج تقريباً <b>${estimated}</b> شهر.`
    :`${progressText} To reach it in <b>${fmt(profile.goalMonths)}</b> months, save <b>${money(required)}</b> monthly. Your current plan takes about <b>${estimated}</b> months.`;
}
function reportLabel(key){const allowed={rent:'rent',internet:'internet',electricity:'electricity',phone:'phone',fuel:'fuel',fixed:'payments',loans:'loans',food:'food',transport:'transport',bills:'billsCat',fun:'fun',other:'other',exceptional:'exceptionalTotal',giving:'giving'};return tr(allowed[key]||'other')}
function buildCycleReport(cycle,receipt){
  const expenses=expensesInCycle(cycle);
  const plan=receipt.planSnapshot||planSnapshot();
  const breakdown=new Map();
  const add=(key,amount)=>{amount=num(amount);if(amount)breakdown.set(key,(breakdown.get(key)||0)+amount)};
  ['rent','internet','electricity','phone','fuel','fixed','loans'].forEach(key=>add(key,plan[key]));
  expenses.forEach(expense=>{
    if(expense.kind==='giving')add('giving',expense.amount);
    else if(expense.kind==='exceptional')add('exceptional',expense.amount);
    else add(expense.category,expense.amount);
  });
  const items=[...breakdown.entries()].map(([key,amount])=>({key,amount})).sort((a,b)=>b.amount-a.amount);
  const totals=completedCycleReport({salary:receipt.amount,plan,expenses}),salary=num(receipt.amount);
  return {id:newId(),start:cycle.start,end:cycle.end,days:cycleProgress(cycle,parseDate(cycle.end)).total,salary,spent:totals.spent,saved:totals.saved,savedPct:pct(totals.saved,totals.income),topKey:items[0]?.key||'other',topAmount:items[0]?.amount||0,breakdown:items,expenses:expenses.map(expense=>({...expense}))};
}
function expenseKindClass(kind){return ['regular','recurring','exceptional','giving'].includes(kind)?kind:'regular'}
function reportExpenseList(report){
  if(!report.expenses.length)return `<div class="empty">${tr('reportEmpty')}</div>`;
  return `<div class="list">${report.expenses.map(expense=>`<div class="rowline expense-row ${expenseKindClass(expense.kind)}"><div><b>${escapeHtml(expense.merchant||tr('expense'))}</b><small>${escapeHtml(expense.date)} • ${escapeHtml(expenseKindLabel(expense))}</small></div><div class="money">${money(expense.amount)}</div></div>`).join('')}</div>`;
}
function reportSummaryText(report){
  return state.settings.lang==='ar'
    ?`تهانينا! لقد أتممت <b>${report.days}</b> يوماً منذ آخر راتب قبضته. استطعت توفير <b class="good">${money(report.saved)}</b>، أي <b>${report.savedPct}%</b> من الراتب المستلم.`
    :`Congratulations! You completed <b>${report.days}</b> days since your last salary. You saved <b class="good">${money(report.saved)}</b>, or <b>${report.savedPct}%</b> of the salary received.`;
}
function reportCard(report,latest=false){
  if(!report)return'';
  return `<div class="card cycle-report ${latest?'latest-report':''}"><div class="section"><div><span class="eyebrow">${tr('cycleComplete')}</span><h3><bdi dir="ltr">${escapeHtml(report.start)} - ${escapeHtml(report.end)}</bdi></h3></div><span class="report-score">${report.savedPct}%</span></div><p class="report-message">${reportSummaryText(report)}</p><div class="report-grid"><div class="metric"><div class="lab">${tr('totalSpent')}</div><div class="val yellow">${money(report.spent)}</div></div><div class="metric"><div class="lab">${tr('topSpending')}</div><div class="val blue">${reportLabel(report.topKey)}</div><span class="pct">${money(report.topAmount)}</span></div></div><div class="breakdown-list">${report.breakdown.map(item=>`<div><span>${reportLabel(item.key)}</span><b>${money(item.amount)}</b></div>`).join('')}</div><p class="copy">${tr('nextCycleWish')}</p><details><summary>${tr('fullReport')}</summary><div class="report-expenses"><h4>${tr('actualExpenses')}</h4>${reportExpenseList(report)}</div></details></div>`;
}
function registerSalary(){
  const date=$('receivedSalaryDate').value,amount=num($('receivedSalaryAmount').value),latest=state.salaryReceipts[state.salaryReceipts.length-1];
  if(!amount){toast(tr('toastSalary'));return}
  if(!confirmUnusual(amount))return;
  if(date>localDate()){toast(tr('salaryDateFuture'));return}
  if(!parseDate(date)){toast(tr('toastFirstDate'));return}
  if(!latest){
    state.salaryReceipts.push({id:newId(),date,amount,planSnapshot:planSnapshot()});
    state.profile.salaryDate=date;
    if(!save())return;
    syncRecurringPayments();
    showTab('dashboard');
    toast(tr('firstSalaryRegistered'),'success');
    return;
  }
  if(date<=latest.date){toast(tr('salaryDateOld'));return}
  const cycle=closedReceiptCycle(latest.date,date);
  if(!cycle){toast(tr('salaryDateOld'));return}
  state.cycleReports.unshift(buildCycleReport(cycle,latest));
  state.salaryReceipts.push({id:newId(),date,amount,planSnapshot:planSnapshot()});
  state.profile.salaryDate=date;
  if(!save())return;
  syncRecurringPayments();
  showTab('dashboard');
  toast(tr('salaryRegistered'),'success');
}
function renderDashboard(){
  const income=cycleIncome(),fixed=fixedCosts(),saving=plannedSaving(),spent=totalCycleSpent();
  const available=cycleStartAvailable(),remaining=salaryRemaining(),cycle=currentCycle();
  const elapsed=cycleProgress(cycle).elapsed;
  const giving=kindTotal('giving'),exceptional=kindTotal('exceptional'),p=state.profile,goalProgress=savingsProgress(p.goalAmount,state.cycleReports);
  $('dashboard').innerHTML=`<div class="card glass hero"><div class="section"><div><h2>${tr('dashTitle')}</h2><p>${tr('dashDesc')}</p></div><span class="cycle-pill">${tr('openCycle')}: <bdi dir="ltr">${cycle.start}</bdi> • ${tr('untilNextSalary')}</span></div><div class="btns"><button class="btn" onclick="showTab('expense')">${tr('addExpense')}</button><button class="btn sec" onclick="showTab('budget')">${tr('viewPlan')}</button></div></div>${dailySummaryCard()}${backupDue()?`<div class="card backup-card"><p class="copy">${tr('backupReminder')}</p><button class="btn" onclick="exportData()">${tr('backupNow')}</button></div>`:''}${balanceOrb(remaining,available)}<div class="card salary-receipt-card"><div class="section"><div><h3>${tr('receivedSalary')}</h3><p class="copy">${tr('receivedSalaryDesc')}</p></div><span class="days-badge">${elapsed}<small>${tr('daysSinceSalary')}</small></span></div><div class="split"><div class="field"><label for="receivedSalaryDate">${tr('newSalaryDate')}</label><input id="receivedSalaryDate" type="date" max="${localDate()}" value="${localDate()}"></div><div class="field"><label for="receivedSalaryAmount">${tr('salaryAmount')}</label><input id="receivedSalaryAmount" data-money inputmode="decimal" value="${display(currentSalary())}"></div></div><button class="btn" onclick="registerSalary()">${tr('registerSalary')}</button></div>${state.cycleReports.length?reportCard(state.cycleReports[0],true):''}<div class="grid cycle-metrics"><div class="metric"><div class="lab">${tr('cycleSalary')}</div><div class="val good">${money(currentSalary())}</div></div><div class="metric"><div class="lab">${tr('cycleSpending')}</div><div class="val ${spent>available?'bad':'yellow'}">${money(spent)}</div><span class="pct">${pct(spent,income)}%</span></div>${giving?`<div class="metric"><div class="lab">${tr('giving')}</div><div class="val good">${money(giving)}</div></div>`:''}${exceptional?`<div class="metric"><div class="lab">${tr('exceptionalTotal')}</div><div class="val yellow">${money(exceptional)}</div></div>`:''}</div><div class="card"><div class="section"><h3>${tr('goal')}</h3><span class="hint">${escapeHtml(p.goalName||tr('generalSave'))}</span></div><p class="copy">${tr('plannedToSave')} <b class="good">${money(saving)}</b> ${tr('monthly')}. ${goalScheduleText(p,saving)}</p><div class="barwrap"><div class="bar" style="width:${p.goalType==='specific'?goalProgress.progress:Math.min(100,pct(saving,income))}%"></div></div></div><div class="card"><div class="section"><h3>${tr('lastExpenses')}</h3><span class="hint"><bdi dir="ltr">${cycle.start}</bdi> • ${tr('openCycle')}</span></div>${expenseList(5)}</div>`;
  attachMoneyFormatting();
}
function categoryLabel(category){return tr({food:'food',transport:'transport',bills:'billsCat',fun:'fun',other:'other'}[category]||'other')}
function categoryOptions(selected='auto',includeAuto=true){const options=[['food','food'],['transport','transport'],['bills','billsCat'],['fun','fun'],['other','other']];return `${includeAuto?`<option value="auto" ${selected==='auto'?'selected':''}>${tr('auto')}</option>`:''}${options.map(([value,key])=>`<option value="${value}" ${selected===value?'selected':''}>${tr(key)}</option>`).join('')}`}
function renderExpense(){
  const editing=state.expenses.find(expense=>expense.id===editingExpenseId);
  const cycle=currentCycle();
  $('expense').innerHTML=`<div class="card"><div class="section"><h3>${editing?tr('editExpense'):tr('addExpense')}</h3><span class="hint">${tr('auto')}</span></div><div class="form"><div class="field"><label for="exAmount">${tr('amount')}</label><input id="exAmount" data-money inputmode="decimal" value="${display(editing?.amount)}"></div><div class="field"><label for="exMerchant">${tr('merchant')}</label><input id="exMerchant" maxlength="100" value="${escapeHtml(editing?.merchant||'')}"></div><div class="split"><div class="field"><label for="exDate">${tr('date')}</label><input id="exDate" type="date" min="${cycle.start}" max="${localDate()}" value="${editing?.date||localDate()}"></div><div class="field"><label for="exCategory">${tr('category')}</label><select id="exCategory">${categoryOptions(editing?.category||'auto')}</select></div></div><div class="btns"><button class="btn" onclick="saveExpense()">${editing?tr('updateExpense'):tr('saveExpense')}</button>${editing?`<button class="btn sec" onclick="cancelExpenseEdit()">${tr('cancel')}</button>`:''}</div></div></div><div class="card giving-card"><div class="section"><div><h3>${tr('specialGiving')}</h3><p class="copy">${tr('specialGivingHint')}</p></div><span class="section-icon">+</span></div><div class="form"><div class="split"><div class="field"><label for="specialType">${tr('paymentType')}</label><select id="specialType"><option value="parents">${tr('parents')}</option><option value="family">${tr('family')}</option><option value="charity">${tr('charity')}</option><option value="gift">${tr('gift')}</option><option value="emergency">${tr('emergency')}</option><option value="exceptional">${tr('exceptional')}</option></select></div><div class="field"><label for="specialAmount">${tr('amount')}</label><input id="specialAmount" data-money inputmode="decimal"></div></div><div class="split"><div class="field"><label for="specialDescription">${tr('merchant')}</label><input id="specialDescription" maxlength="100"></div><div class="field"><label for="specialDate">${tr('date')}</label><input id="specialDate" type="date" min="${cycle.start}" max="${localDate()}" value="${localDate()}"></div></div><button class="btn giving-btn" onclick="addSpecialPayment()">${tr('savePayment')}</button></div></div><div class="card"><div class="section"><h3>${tr('allExpenses')}</h3><span class="hint">${tr('newest')}</span></div>${expenseList(50)}</div>`;
  attachMoneyFormatting();
}
function rememberMerchantCategory(merchant,category){const key=merchant.trim().toLowerCase();if(key&&category!=='auto')state.merchantCategories[key]=category}
function validExpenseDate(date){return !!parseDate(date)&&inCycle(date,currentCycle())}
function budgetAlert(category,spent,limit){if(!limit)return'';const level=spent>=limit?'100':spent>=limit*.8?'80':'';if(!level)return'';const key=`${currentCycle().start}:${category}:${level}`;if(state.budgetAlerts[key])return'';state.budgetAlerts[key]=true;return level==='100'?tr('budgetOver'):tr('budgetNear')}
function saveExpense(){const amount=num($('exAmount').value),merchant=$('exMerchant').value.trim(),date=$('exDate').value,chosen=$('exCategory').value;if(!amount){toast(tr('toastAmount'));return}if(!validExpenseDate(date)){toast(tr('toastDate'));return}const category=chosen==='auto'?classifyMerchant(merchant,state.merchantCategories):chosen;rememberMerchantCategory(merchant,category);const existing=state.expenses.find(expense=>expense.id===editingExpenseId);if(existing){Object.assign(existing,{amount,merchant,category,date});editingExpenseId=null}else state.expenses.unshift({id:newId(),amount,merchant,category,date,kind:'regular'});const limit=num(state.categoryBudgets[category]);cycleCache=null;const spent=categorySpent(category),alert=existing?'':budgetAlert(category,spent,limit);if(!save())return;showTab('dashboard');if(existing)toast(tr('expenseUpdated'),'success');else if(alert)toast(`${alert}: ${categoryLabel(category)}`);else toast(tr('toastExpense'),'success')}
function addExpense(){saveExpense()}
function editExpense(id){editingExpenseId=id;showTab('expense')}
function cancelExpenseEdit(){editingExpenseId=null;renderExpense()}
function addSpecialPayment(){const amount=num($('specialAmount').value),subtype=$('specialType').value,date=$('specialDate').value,description=$('specialDescription').value.trim();if(!amount){toast(tr('toastAmount'));return}if(!validExpenseDate(date)){toast(tr('toastDate'));return}const givingTypes=new Set(['parents','family','charity','gift']),kind=givingTypes.has(subtype)?'giving':'exceptional';state.expenses.unshift({id:newId(),amount,merchant:description,category:'other',date,kind,subtype});if(!save())return;showTab('dashboard');toast(tr('specialSaved'),'success')}
function expenseKindLabel(expense){const subtypes=new Set(['parents','family','charity','gift','emergency','exceptional']);if(expense.kind==='giving')return tr(subtypes.has(expense.subtype)?expense.subtype:'giving');if(expense.kind==='exceptional')return tr(subtypes.has(expense.subtype)?expense.subtype:'exceptional');if(expense.kind==='recurring')return tr('recurringExpense');return categoryLabel(expense.category)}
function expenseList(limit){const arr=cycleExpenses().slice(0,limit);if(!arr.length)return `<div class="empty">${tr('noExpenses')}</div>`;return `<div class="list">${arr.map(e=>`<div class="rowline expense-row ${expenseKindClass(e.kind)}"><div><b>${escapeHtml(e.merchant||tr('expense'))}</b><small>${escapeHtml(e.date)} • ${escapeHtml(expenseKindLabel(e))}</small></div><div class="amount-actions"><div class="money">${money(e.amount)}</div><div class="expense-actions"><button class="chip mini" onclick="editExpense(${Number(e.id)})">${tr('edit')}</button><button class="chip mini" onclick="deleteExpense(${Number(e.id)})">${tr('delete')}</button></div></div></div>`).join('')}</div>`}
function deleteExpense(id){if(!confirm(tr('deleteExpenseConfirm')))return;state.expenses=state.expenses.filter(e=>e.id!==id);if(editingExpenseId===id)editingExpenseId=null;save();renderAll()}
function categoryBudgetRows(){return ['food','transport','bills','fun','other'].map(category=>{const limit=num(state.categoryBudgets[category]),spent=categorySpent(category),progress=limit?pct(spent,limit):0,status=progress>=100?'danger':progress>=80?'warning':'';return `<div class="budget-category"><div class="section"><b>${categoryLabel(category)}</b><span class="money">${limit?`${money(spent)} / ${money(limit)}`:`${money(spent)} • ${tr('noLimit')}`}</span></div>${limit?`<div class="barwrap" aria-label="${progress}%"><div class="bar ${status==='danger'?'danger-bar':status==='warning'?'warn':''}" style="width:${Math.min(100,progress)}%"></div></div>${status?`<span class="status-tag ${status} mini"><i aria-hidden="true">${status==='danger'?'×':'!'}</i>${tr(status==='danger'?'budgetOver':'budgetNear')}</span>`:''}`:''}</div>`}).join('')}
function recurringList(){if(!state.recurringPayments.length)return `<div class="empty">${tr('noRecurring')}</div>`;return `<div class="list">${state.recurringPayments.map(payment=>`<div class="rowline"><div><b>${escapeHtml(payment.name)}</b><small>${categoryLabel(payment.category)} • ${tr('paymentDay')} ${payment.day}</small></div><div class="amount-actions"><div class="money">${money(payment.amount)}</div><button class="chip mini" onclick="deleteRecurring(${Number(payment.id)})">${tr('delete')}</button></div></div>`).join('')}</div>`}
function renderBudget(){
  const income=cycleIncome(),fixed=fixedCosts(),saving=plannedSaving(),variable=cycleStartAvailable(),spent=totalCycleSpent();
  const items=[[tr('rent'),state.profile.rent],[tr('internet'),state.profile.internet],[tr('electricity'),state.profile.electricity],[tr('phone'),state.profile.phone],[tr('fuel'),state.profile.fuel],[tr('payments'),state.profile.fixed],[tr('loans'),state.profile.loans],[tr('saving'),saving],[tr('remainSpend'),variable]];
  $('budget').innerHTML=`<div class="card"><div class="section"><h3>${tr('budgetTitle')}</h3><span class="hint">${money(income)}</span></div>${items.filter(item=>num(item[1])>0).map(([name,value])=>{const percentage=pct(value,income);return `<div class="rowline block"><div class="section"><b>${name}</b><span class="money">${money(value)} • ${percentage}%</span></div><div class="barwrap"><div class="bar ${percentage>45?'warn':''}" style="width:${Math.min(100,percentage)}%"></div></div></div>`}).join('')}<p class="copy">${tr('totalCycleSpending')}: <b>${money(spent)}</b> ${tr('from')} <b>${money(variable)}</b>.</p></div><div class="card"><div class="section"><div><h3>${tr('categoryBudgets')}</h3><p class="copy">${tr('categoryBudgetHint')}</p></div></div><div class="category-budget-grid">${['food','transport','bills','fun','other'].map(category=>`<div class="field"><label for="budget-${category}">${categoryLabel(category)}</label><input id="budget-${category}" data-money inputmode="decimal" value="${display(state.categoryBudgets[category])}"></div>`).join('')}</div><button class="btn" onclick="saveCategoryBudgets()">${tr('saveBudgets')}</button><div class="budget-progress">${categoryBudgetRows()}</div></div><div class="card"><div class="section"><div><h3>${tr('recurring')}</h3><p class="copy">${tr('recurringHint')} ${tr('duplicateCommitmentHint')}</p></div></div><div class="form"><div class="field"><label for="recurringName">${tr('paymentName')}</label><input id="recurringName" maxlength="80"></div><div class="split"><div class="field"><label for="recurringAmount">${tr('amount')}</label><input id="recurringAmount" data-money inputmode="decimal"></div><div class="field"><label for="recurringDay">${tr('paymentDay')}</label><input id="recurringDay" type="number" min="1" max="31" inputmode="numeric" value="${currentCycle().salaryDay}"></div></div><div class="field"><label for="recurringCategory">${tr('category')}</label><select id="recurringCategory">${categoryOptions('bills',false)}</select></div><button class="btn sec" onclick="addRecurringPayment()">${tr('addRecurring')}</button></div>${recurringList()}</div>`;
  attachMoneyFormatting();
}
function saveCategoryBudgets(){['food','transport','bills','fun','other'].forEach(category=>state.categoryBudgets[category]=num($(`budget-${category}`).value));if(!save())return;renderBudget();toast(tr('budgetsSaved'),'success')}
function addRecurringPayment(){const name=$('recurringName').value.trim(),amount=num($('recurringAmount').value),day=Math.min(31,Math.max(1,num($('recurringDay').value)||1)),category=$('recurringCategory').value;if(!name||!amount){toast(tr('toastAmount'));return}state.recurringPayments.push({id:newId(),name,amount,day,category,active:true});if(!save())return;syncRecurringPayments();showTab('budget');toast(tr('recurringSaved'),'success')}
function deleteRecurring(id){if(!confirm(tr('deleteRecurringConfirm')))return;state.recurringPayments=state.recurringPayments.filter(payment=>payment.id!==id);state.expenses.forEach(expense=>{if(expense.recurringId===id)expense.recurringId=null});if(!save())return;showTab('budget')}
function backupDue(){const last=parseDate(state.settings.lastBackupAt),days=last?Math.floor((parseDate(localDate())-last)/86400000):Infinity;return state.expenses.length>0&&days>=30}
function renderSettings(){const cycle=currentCycle(),locked=hasFinancialData();$('settings').innerHTML=`<div class="card"><div class="section"><div><h3>${tr('openCycle')}</h3><p class="copy">${tr('untilNextSalary')}</p></div><span class="cycle-pill"><bdi dir="ltr">${cycle.start}</bdi></span></div></div>${backupDue()?`<div class="card backup-card"><p class="copy">${tr('backupReminder')}</p><button class="btn" onclick="exportData()">${tr('backupNow')}</button></div>`:''}<div class="reports-stack"><div class="section"><h3>${tr('cycleReports')}</h3><span class="hint">${state.cycleReports.length}</span></div>${state.cycleReports.length?state.cycleReports.map(report=>reportCard(report)).join(''):`<div class="card empty">${tr('noReports')}</div>`}</div><div class="card"><div class="section"><h3>${tr('privacy')}</h3><span class="hint">${tr('local')}</span></div><p class="copy">${tr('privacyText')}</p><div class="field" style="margin-top:12px"><label>${tr('currency')}</label><select ${locked?'disabled aria-disabled="true"':''} onchange="setCurrency(this.value)">${currencies.map(c=>`<option value="${c}" ${state.settings.currency===c?'selected':''}>${currencyOption(c)}</option>`).join('')}</select>${locked?`<span class="hint">${tr('currencyLocked')}</span>`:''}</div><div class="btns"><button class="btn sec" onclick="exportData()">${tr('export')}</button><button class="btn sec" onclick="document.getElementById('importFile').click()">${tr('import')}</button><button class="btn ghost full" onclick="restartWizard()">${tr('editPlan')}</button><button class="btn danger full" onclick="resetAll()">${tr('reset')}</button></div><input id="importFile" type="file" accept="application/json" class="hidden" onchange="importData(event)"></div>`}
function exportData(){state.settings.lastBackupAt=localDate();if(!save())return;const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(state,null,2)],{type:'application/json'}));a.download='mezan-backup.json';a.click();URL.revokeObjectURL(a.href);if(activeTab==='settings')renderSettings()}
function arrayCount(value){return Array.isArray(value)?value.length:0}
function importSkippedCount(raw,imported){return ['expenses','recurringPayments','salaryReceipts','cycleReports'].reduce((sum,key)=>sum+Math.max(0,arrayCount(raw[key])-arrayCount(imported[key])),0)}
function importData(ev){const f=ev.target.files[0];if(!f)return;if(f.size>2_000_000){toast(tr('importTooLarge'));ev.target.value='';return}const r=new FileReader();r.onload=()=>{try{const raw=JSON.parse(r.result),imported=MezanStorage.normalize(raw),skipped=importSkippedCount(raw,imported);state=imported;if(save()){init();toast(skipped?tr('importSkipped')(skipped):tr('importOk'),skipped?'error':'success')}}catch{state=JSON.parse(JSON.stringify(persistedState));toast(state.settings.lang==='ar'?'ملف النسخة الاحتياطية غير صالح':'Invalid backup file')}finally{ev.target.value=''}};r.readAsText(f)}
let resetDialogReturnFocus=null;
function resetAll(){
  resetDialogReturnFocus=document.activeElement;
  const overlay=document.createElement('div');
  overlay.className='dialog-overlay';
  overlay.id='resetDialog';
  overlay.innerHTML=`<section class="confirm-dialog" role="dialog" aria-modal="true" aria-labelledby="resetDialogTitle" aria-describedby="resetDialogDesc"><div class="dialog-icon" aria-hidden="true">!</div><h2 id="resetDialogTitle">${tr('resetTitle')}</h2><p id="resetDialogDesc">${tr('resetWarning')}</p><label for="resetConfirmInput">${tr('resetType')}</label><input id="resetConfirmInput" autocomplete="off"><div class="btns"><button class="btn sec" id="cancelReset">${tr('cancel')}</button><button class="btn danger" id="confirmReset" disabled>${tr('resetConfirm')}</button></div></section>`;
  document.body.appendChild(overlay);
  const input=$('resetConfirmInput'),confirmButton=$('confirmReset'),cancelButton=$('cancelReset'),dialog=overlay.querySelector('.confirm-dialog');
  const close=()=>{overlay.remove();resetDialogReturnFocus?.focus()};
  input.addEventListener('input',()=>confirmButton.disabled=input.value.trim()!==tr('resetWord'));
  cancelButton.addEventListener('click',close);
  overlay.addEventListener('click',event=>{if(event.target===overlay)close()});
  confirmButton.addEventListener('click',()=>{const settings={...state.settings};MezanStorage.clear();state=MezanStorage.defaults(settings);persistedState=JSON.parse(JSON.stringify(state));save();close();init()});
  dialog.addEventListener('keydown',event=>{
    if(event.key==='Escape'){event.preventDefault();close();return}
    if(event.key!=='Tab')return;
    const controls=[input,cancelButton,confirmButton].filter(control=>!control.disabled);
    const first=controls[0],last=controls[controls.length-1];
    if(event.shiftKey&&document.activeElement===first){event.preventDefault();last.focus()}
    else if(!event.shiftKey&&document.activeElement===last){event.preventDefault();first.focus()}
  });
  input.focus();
}
function updateConnectionStatus(announce=false){
  const banner=$('connectionBanner');
  if(navigator.onLine){banner.classList.add('hidden');if(announce)toast(tr('onlineAgain'),'success')}
  else{banner.textContent=tr('offlineNow');banner.classList.remove('hidden')}
}
function showTab(id){activeTab=id;renderTab(id);document.querySelectorAll('.panel').forEach(p=>p.classList.add('hidden'));$(id).classList.remove('hidden');document.querySelectorAll('.tab').forEach(b=>{const active=b.dataset.tab===id;b.classList.toggle('active',active);b.setAttribute('aria-current',active?'page':'false')});window.scrollTo({top:0,behavior:'smooth'})}
if('serviceWorker'in navigator)window.addEventListener('load',()=>navigator.serviceWorker.register('./sw.js').catch(()=>{}));
window.addEventListener('online',()=>updateConnectionStatus(true));
window.addEventListener('offline',()=>updateConnectionStatus());
updateConnectionStatus();
init();
